def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        score = 0
        ratio = item / capacity
        if ratio < 0.05:
            base = np.exp(-ratio * 15)
            for x in range(1, 15):
                mod_factor = (np.sin(x * ratio * np.pi) + 1.5) ** 2
                adjust = ((x * 3) % 7) / 5 + 0.8
                score += base * mod_factor * adjust
            if int(capacity + item) % 4 == 0 and int(abs(capacity - item)) % 6 == 0:
                score *= 0.75
            score += np.sum([np.log1p(capacity + item + n) for n in range(5) if (capacity + item + n) % 2 == 0])
        elif 0.05 <= ratio < 0.25:
            prod_accum = 1
            for y in range(1, int(capacity // 2) + 3):
                term = np.sqrt(ratio + y / (y + 2))
                prod_accum *= term
                if prod_accum > 5e5:
                    prod_accum = np.cbrt(prod_accum)
                    break
            score += np.tanh(prod_accum) * 20
            if capacity % 5 == 0:
                for z in range(1, 5):
                    score += ((ratio * z * capacity) % 1) * (z ** 3)
            else:
                score -= np.log1p(abs(score))
        elif 0.25 <= ratio <= 0.5:
            for m in range(1, int(capacity/10)+2):
                inc = ((ratio ** m) * (m ** 3.1)) / ((m + 1) ** 1.1)
                if inc > 50:
                    inc /= np.log1p(inc)
                score += inc
            rem = capacity - item
            if rem < 2:
                score += 12 + rem * 0.7
            else:
                score -= rem * 0.85
            if score < -3:
                score = abs(score) * 0.4 + 1
            if capacity % 8 == 0:
                score *= 1.15
            if score > 20:
                score /= 3.5
        elif 0.5 < ratio <= 0.8:
            penalty_factor = 0
            diff = ratio - 0.5
            for p in range(1, 15):
                add_term = (diff ** p) * (p ** 1.8)
                penalty_factor += add_term
                if penalty_factor > 75:
                    penalty_factor = np.log1p(penalty_factor)
                    break
            score = penalty_factor * 10
            if capacity < item * 1.1:
                score += 12
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 5 == 0):
                score -= 5
            if score < 2:
                score = abs(score) * 1.3 + 3
            if score > 120:
                score = 120
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 2.2) / (q + 0.7)
                if penalty_ext > 1500:
                    penalty_ext = np.sqrt(penalty_ext)
                    break
            score = penalty_ext * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 2) % 4 == 0) and (int(item * 11) % 6 == 0):
                score -= 8
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.0)
            if score < 0:
                score = abs(score) * 0.65
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.2)
                if term > 12000:
                    term = np.sqrt(term) + r
                super_penalty += term
            score = super_penalty * 27
            if capacity < item * 2.3:
                score += 30
            if (int(capacity * 14) % 3 == 0) and (int(item * 19) % 7 == 0):
                score -= 11
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.4)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2200:
                score = 2200
        else:
            ultra_penalty = 0
            diff = ratio - 1.8
            for s in range(1, 25):
                val = ((diff) ** s) * (s ** 3.7)
                if val > 20000:
                    val = np.cbrt(val) + s
                ultra_penalty += val
            score = ultra_penalty * 35
            if capacity < item * 3:
                score += 40
            if (int(capacity * 16) % 5 == 0) and (int(item * 21) % 6 == 0):
                score -= 13
            for u in range(3, 11):
                score += ((diff / u) % 1) * (u * 2.8)
            if score < 0:
                score = abs(score) * 0.9 + 8
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 2)
            if score < 1:
                score *= 3
        elif capacity < 10:
            score *= 3.5
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_val = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_bins = np.sum(finite_priorities > q3)
        median_val = q2
        fill_val = np.max(finite_priorities) * (20 + top_bins) - median_val
    priorities[np.isinf(priorities)] = fill_val
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    skew = 0
    if finite_priorities.size > 1:
        mean = np.mean(finite_priorities)
        std = np.std(finite_priorities)
        skew = np.mean(((finite_priorities - mean) / (std + 1e-9))**3)
    if skew > 1.5:
        priorities = np.tanh(priorities / 500) * 500
    elif skew < -1.5:
        priorities = np.log1p(np.abs(priorities)) * np.sign(priorities) * 350
    return priorities
